const express = require('express');
const OpenApiValidator = require('express-openapi-validator');
const path = require('path');

const app = express();
app.use(express.json());

// Install OpenAPI validator middleware
app.use(
  OpenApiValidator.middleware({
    apiSpec: path.join(__dirname, 'openapi.yaml'),

    // CRITICAL SECURITY SETTINGS
    validateRequests: {
      allowUnknownQueryParameters: false,  // Reject extra query params
      coerceTypes: false,                  // Disable type coercion to prevent bypass
      removeAdditional: false              // Don't silently remove - fail explicitly
    },
    validateResponses: {
      removeAdditional: 'failing',         // Validate responses don't leak data
      coerceTypes: false
    },
    validateSecurity: {
      handlers: {
        bearerAuth: async (req, scopes, schema) => {
          // Custom JWT validation
          const token = req.headers.authorization?.split(' ')[1];
          if (!token) throw new Error('No token provided');

          const decoded = verifyJWT(token);
          req.user = decoded;

          // Verify scopes
          if (scopes.length && !scopes.some(s => decoded.scopes?.includes(s))) {
            throw new Error('Insufficient permissions');
          }
          return true;
        }
      }
    },

    // Enable strict validation
    validateFormats: 'full',

    // Custom error handler
    unknownFormats: ['int64', 'uuid']  // Whitelist custom formats
  })
);

// Define routes AFTER validator middleware
app.post('/users', async (req, res) => {
  // At this point, req.body is guaranteed to match OpenAPI schema
  // No extra properties, correct types, all required fields present

  const { username, email, password } = req.body;

  // Explicit property allowlist (defense in depth)
  const userData = {
    username,
    email,
    password: await hashPassword(password),
    createdAt: new Date(),
    role: 'user',  // NEVER allow role from request
    isAdmin: false // NEVER allow isAdmin from request
  };

  const user = await db.users.create(userData);

  // Return only safe fields
  res.status(201).json({
    id: user.id,
    username: user.username,
    email: user.email,
    createdAt: user.createdAt
  });
});

// Global error handler for validation failures
app.use((err, req, res, next) => {
  // OpenAPI validation errors
  if (err.status === 400 && err.errors) {
    return res.status(400).json({
      error: 'Validation failed',
      message: 'Request does not match API specification',
      // Don't expose detailed schema in production
      details: process.env.NODE_ENV === 'development' ? err.errors : undefined
    });
  }

  // Security errors
  if (err.status === 401 || err.status === 403) {
    return res.status(err.status).json({
      error: err.message
    });
  }

  next(err);
});

app.listen(3000);

